mapper.select:
select convert(cast(p.`SFZH` as char) using utf8mb4) collate utf8mb4_unicode_ci as idCard, date_format(max(coalesce(p.`JCRQ`, p.`JDRQ`, l.`JLRQ`, p.`UpDateTime`)), '%Y-%m-%d') as latestExamDate from ods_tj_jcxx p left join ods_tj_jlb l on l.`StudyID` = p.`ID` where p.`SFZH` in
#{idCard}
group by p.`SFZH`

select src.encrypted_id_card as encryptedIdCard, date_format(max(coalesce(p.`JCRQ`, p.`JDRQ`, l.`JLRQ`, p.`UpDateTime`)), '%Y-%m-%d') as latestExamDate from (
select convert(cast(#{encryptedIdCard} as char) using utf8mb4) collate utf8mb4_unicode_ci as encrypted_id_card, convert(cast(AES_DECRYPT_ECB(#{encryptedIdCard}, 'SecuR2`4LeCzCoRe') as char) using utf8mb4) collate utf8mb4_unicode_ci as plain_id_card
) src left join ods_tj_jcxx p on p.`SFZH` = src.plain_id_card left join ods_tj_jlb l on l.`StudyID` = p.`ID` group by src.encrypted_id_card

select
from ods_tj_jcxx p left join ods_tj_jlb l on l.`StudyID` = p.`ID` left join ods_tj_xmzh x on x.`XMDM` = p.`ZHXMDM`
order by coalesce(p.`JCRQ`, p.`JDRQ`, l.`JLRQ`, p.`UpDateTime`) desc, p.`ID` desc limit #{request.offset}, #{request.size}
